// 5 次元 typedef 配列ローカル変数の最深 stride チェック。
// a[1][1][1][1][1] - a[0][0][0][0][0] = 31 - 1 = 30
// 期待: exit=0
#include <assert.h>
typedef int M5[2][2][2][2][2];
int main(void) {
    M5 a;
    a[1][1][1][1][1] = 31;
    a[0][0][0][0][0] = 1;
    assert(a[1][1][1][1][1] - a[0][0][0][0][0] == 30);
    return 0;
}
